async function run(params, api) {
  var results = [];
  for (var i = 0; i < params.urls.length; i++) {
    var url = params.urls[i];
    var start = Date.now();
    try {
      var body = await api.httpGet(url);
      var elapsed = Date.now() - start;
      results.push({ url: url, status: 'up', response_time_ms: elapsed, body_preview: body.slice(0, 500) });
    } catch (err) {
      var elapsed2 = Date.now() - start;
      results.push({ url: url, status: 'down', response_time_ms: elapsed2, error: String(err).slice(0, 200) });
    }
  }
  return JSON.stringify(results, null, 2);
}
